def execute_extraction_pipeline(output_filename: str = "dreams_dataset.json") -> None:
    """
    Executes regex-based character extraction across the source string payload.
    Maps matches to unified schemas and writes a clean JSON file to disk.
    """
    # Regex parsing logic: Locates the ID flag (#0000) and extracts 
    # the textual payload up until the site's trailing word count tracker.
    regex_parsing_pattern = r'(#\d{4})\s*\n*(.*?)\s*\(\d+\s*words\)(?=\s*#\d{4}|$)'
    extracted_matches = re.findall(regex_parsing_pattern, RAW_CORPUS_SOURCE, re.DOTALL)
    
    normalized_records_list: List[Dict[str, Any]] = []
    
    for dream_id, narrative_text in extracted_matches:
        # Standardize strings by cleaning line breaks and calculating metric word arrays
        sanitized_string = narrative_text.strip().replace("\n", " ")
        computed_length = len(sanitized_string.split())
        
        # Build programmatic object instances conforming to core validation schemas
        structured_schema = {
            "id": dream_id.replace("#", ""),
            "metadata": {
                "source_dataset": "Hall/VdC Normative Series (Female)",
                "length_tokens": computed_length
            },
            "payload": {
                "manifest_content": sanitized_string
            }
        }
        normalized_records_list.append(structured_schema)
        
    # Open file context and serialize downstream objects to disk using standard UTF-8 guidelines
    with open(output_filename, 'w', encoding='utf-8') as database_stream:
        json.dump(normalized_records_list, database_stream, indent=4, ensure_ascii=False)
        
    print("==========================================================")
    print(f"PIPELINE SUCCESSFUL: Saved to '{output_filename}'")
    print(f"TOTAL TEST RECORDS PARSED AND STORED: {len(normalized_records_list)}")
    print("==========================================================")

if __name__ == "__main__":
    execute_extraction_pipeline()